			end
		end)

		local panel
		local outsideConn
		local function closePanel()
			if not panel then return end
			local p = panel
			panel = nil
			_ddCurrent = nil
			if outsideConn then outsideConn:Disconnect(); outsideConn = nil end
			tween(p, { Size = UDim2.new(0, 190, 0, 0) }, TI.FAST)
			task.delay(0.15, function() p:Destroy() end)
		end

		local function openPanel()
			if panel then closePanel(); return end
			closeOpenDropdown()
			local layer = dropdownLayer(header)
			if not layer then return end

			local names = Win.ListConfigs()
			if #names == 0 then names = { cfgCurrent } end
			local autoName = Win.GetAutoload()

			local ROWS_H = #names * 28
			local FOOT_H = 34
			local fullH = ROWS_H + FOOT_H + 12
			panel = Create("Frame", {
				Position = UDim2.new(0, pill.AbsolutePosition.X, 0, pill.AbsolutePosition.Y + pill.AbsoluteSize.Y + 6),
				Size = UDim2.new(0, 190, 0, 0),
				BackgroundColor3 = THEME.Element,
				BorderSizePixel = 0,
				ClipsDescendants = true,
				ZIndex = 50001,
				Parent = layer,
			}, { corner(10), stroke(THEME.ElementStroke, 1, 0.25), padXY(6, 6) })
			_ddCurrent = { close = closePanel }
			tween(panel, { Size = UDim2.new(0, 190, 0, fullH) }, TI.EXP)

			outsideConn = UserInputService.InputBegan:Connect(function(input)
				if input.UserInputType ~= Enum.UserInputType.MouseButton1 and input.UserInputType ~= Enum.UserInputType.Touch then return end
				if not panel then return end
				local p = input.Position
				local ap, as = panel.AbsolutePosition, panel.AbsoluteSize
				local bp, bs = pill.AbsolutePosition, pill.AbsoluteSize
				local inPanel = p.X >= ap.X and p.X <= ap.X + as.X and p.Y >= ap.Y and p.Y <= ap.Y + as.Y
				local inPill = p.X >= bp.X and p.X <= bp.X + bs.X and p.Y >= bp.Y and p.Y <= bp.Y + bs.Y
				if not inPanel and not inPill then closePanel() end
			end)

			for i, name in ipairs(names) do
				local isAuto = (name == autoName)
				local rowBtn = Create("TextButton", {
					Position = UDim2.new(0, 0, 0, (i - 1) * 28),
					Size = UDim2.new(1, 0, 0, 28),
					BackgroundColor3 = THEME.ElementHover,
					BackgroundTransparency = 1,
					AutoButtonColor = false,
					Font = (name == cfgCurrent) and FONT_MED or FONT,
					Text = (isAuto and "\u{2605} " or "") .. name,
					TextColor3 = (name == cfgCurrent) and THEME.Text or THEME.SubText,
					TextSize = 14,
					TextXAlignment = Enum.TextXAlignment.Left,
					ZIndex = 50002,
					Parent = panel,
				}, { corner(7), padXY(8, 0) })
				rowBtn.MouseEnter:Connect(function() tween(rowBtn, { BackgroundTransparency = 0 }, TI.HOVER) end)
				rowBtn.MouseLeave:Connect(function() tween(rowBtn, { BackgroundTransparency = 1 }, TI.HOVER) end)
				rowBtn.MouseButton1Click:Connect(function()
					setCurrent(name)
					Win.LoadConfig(name)
					closePanel()
				end)
				rowBtn.MouseButton2Click:Connect(function()
					Win.SetAutoload(isAuto and nil or name)
					NEMESIS.Notify({
						title = "Autoload",
						content = isAuto and "cleared" or (name .. " loads on start"),
						duration = 2,
					})
					closePanel()
				end)
			end

			-- footer actions: new / save / delete
			local function actionBtn(text, xFrac, cb)
				local b = Create("TextButton", {
					Position = UDim2.new(xFrac, xFrac > 0 and 3 or 0, 1, -28),
					Size = UDim2.new(1 / 3, xFrac > 0 and -3 or -3, 0, 26),
					BackgroundColor3 = THEME.ElementHover,
					AutoButtonColor = false,
					Font = FONT_MED,
					Text = text,
					TextColor3 = THEME.SubText,
					TextSize = 13,
					ZIndex = 50002,
					Parent = panel,
				}, { corner(7) })
				b.MouseEnter:Connect(function() tween(b, { TextColor3 = THEME.Text }, TI.HOVER) end)
				b.MouseLeave:Connect(function() tween(b, { TextColor3 = THEME.SubText }, TI.HOVER) end)
				b.MouseButton1Click:Connect(cb)
				return b
			end
			actionBtn("New", 0, function()
				local n = 1
				local taken = {}
				for _, existing in ipairs(Win.ListConfigs()) do taken[existing] = true end
				while taken["config" .. n] do n = n + 1 end
				local name = "config" .. n
				if Win.SaveConfig(name) then
					setCurrent(name)
					NEMESIS.Notify({ title = "Config created", content = name, duration = 2 })
				end
				closePanel()
			end)
			actionBtn("Save", 1 / 3, function()
				if Win.SaveConfig(cfgCurrent) then
					NEMESIS.Notify({ title = "Config saved", content = cfgCurrent, duration = 2 })
				end
				closePanel()
			end)
			actionBtn("Del", 2 / 3, function()
				Win.DeleteConfig(cfgCurrent)
				NEMESIS.Notify({ title = "Config deleted", content = cfgCurrent, duration = 2 })
				local left = Win.ListConfigs()
				setCurrent(left[1] or "default")
				closePanel()
			end)
		end

		pill.MouseButton1Click:Connect(openPanel)
		pill.MouseEnter:Connect(function() tween(pill, { BackgroundColor3 = THEME.ElementHover }, TI.HOVER) end)
		pill.MouseLeave:Connect(function() tween(pill, { BackgroundColor3 = THEME.Element }, TI.HOVER) end)
	end

	-- autoload: apply the marked config shortly after the script builds its UI
	if cfgFolder then
		task.delay(0.7, function()
			local name = Win.GetAutoload()
			if name then
				if updatePill then updatePill(name) else cfgCurrent = name end
				pcall(Win.LoadConfig, name)
			end
		end)
	end

	-- ===== runtime theme switching =====
	-- Win.SetTheme("Light") / Win.SetTheme({ Background = ... }) recolours the
	-- live UI by matching every gui object's colours against the outgoing
	-- palette, then updates THEME so anything built later uses the new one
	local THEME_COLOR_PROPS = { "BackgroundColor3", "TextColor3", "ImageColor3", "PlaceholderColor3", "ScrollBarImageColor3", "Color" }
	function Win.SetTheme(theme)
		local palette = (type(theme) == "string") and NEMESIS.Themes[theme] or theme
		if type(palette) ~= "table" then return false end

		local keys = {}
		for k in pairs(NEMESIS.Themes.Dark) do keys[#keys + 1] = k end
		table.sort(keys)
		local oldByHex = {}
		for _, k in ipairs(keys) do
			local c = THEME[k]
			if typeof(c) == "Color3" then
				local h = hexOf(c)
				if oldByHex[h] == nil then oldByHex[h] = k end
			end
		end

		for k, v in pairs(palette) do
			if k ~= "Accent" then THEME[k] = v end
		end

		local function recolor(inst)
			for _, prop in ipairs(THEME_COLOR_PROPS) do
				pcall(function()
					local cur = inst[prop]
					if typeof(cur) == "Color3" then
						local key = oldByHex[hexOf(cur)]
						if key and typeof(THEME[key]) == "Color3" then
							inst[prop] = THEME[key]
						end
					end
				end)
			end
		end
		pcall(function()
			for _, inst in ipairs(screenGui:GetDescendants()) do
				recolor(inst)
			end
		end)

		-- rebuild the colour-embedding rich text + active page tint
		if activeTab and activeTab.activePage then
			pcall(function() applyPageVisual(activeTab, activeTab.activePage, false) end)
			pcall(function() setCrumb(activeTab, activeTab.activePage) end)
		end
		return true
	end

	-- small live setters
	function Win.SetTitle(t) wordmark.Text = string.upper(tostring(t or "NEMESIS")) end
	function Win.SetGame(t) gameLabel.Text = tostring(t or "") end
	function Win.SetStatus(t) statusLabel.Text = tostring(t or "") end

	-- Tab / Group / Page builders
	function Win.Tab(name, icon, ...)
		-- Tolerate method-style calls: Window:Tab("X") passes Window as the first
		-- arg, so shift it off (otherwise the name becomes the table).
		if name == Win then name, icon = icon, ... end
		local tab = { name = tostring(name or "Tab"), pages = {}, activePage = nil }

		-- a full-height hairline sits BETWEEN tabs (its own list item, so it never
		-- interferes with each button's AutomaticSize.X - that was clipping text).
		-- only the dividers touching the active segment are shown (like the mockup).
		if #tabs > 0 then
			tabBarOrder = tabBarOrder + 1
			tab.leftDivider = Create("Frame", {
				Size = UDim2.new(0, 1, 1, 0),
				BackgroundColor3 = Color3.fromRGB(58, 60, 74),
				BorderSizePixel = 0,
				Visible = (activeTab == tabs[#tabs]),
				LayoutOrder = tabBarOrder,
				Parent = tabBar,
			})
		end

		-- top-tab segment: a transparent button holds a rounded fill (behind) and a
		-- text label (in front). the executor doesn't clip children to the bar's
		-- rounded corners, so the fill rounds its own corner(8); the corner(s) that
		-- face a NEIGHBOUR tab are then squared off so only the bar's outer edges
		-- stay rounded (leftmost rounds left, rightmost rounds right, middle square).
		local TAB_FILL = Color3.fromRGB(40, 42, 53)
		local hasLeft = #tabs > 0

		tabBarOrder = tabBarOrder + 1
		local btn = Create("TextButton", {
			Size = UDim2.new(0, 0, 1, 0),
			AutomaticSize = Enum.AutomaticSize.X,
			BackgroundTransparency = 1,
			AutoButtonColor = false,
			Text = "",
			LayoutOrder = tabBarOrder,
			Parent = tabBar,
		})
		local fill = Create("Frame", {
			Size = UDim2.new(1, 0, 1, 0),
			BackgroundColor3 = TAB_FILL,
			BackgroundTransparency = 1,
			BorderSizePixel = 0,
			ZIndex = 1,
			Parent = btn,
		}, { corner(8) })
		local label = Create("TextLabel", {
			Size = UDim2.new(0, 0, 1, 0),
			AutomaticSize = Enum.AutomaticSize.X,
			BackgroundTransparency = 1,
			Font = FONT_MED,
			Text = tostring(name or "Tab"),
			TextColor3 = THEME.SubText,
			TextSize = 16,
			ZIndex = 2,
			Parent = btn,
		}, {
			Create("UIPadding", { PaddingLeft = UDim.new(0, 22), PaddingRight = UDim.new(0, 22) }),
		})

		-- square off one inner corner: an 8px patch of the fill colour over the
		-- rounded corner on the side that faces a neighbour (sits in the padding
		-- margin, clear of the centred label, so it never covers text)
		local function squareOff(targetFill, side)
			return Create("Frame", {
				AnchorPoint = side == "R" and Vector2.new(1, 0.5) or Vector2.new(0, 0.5),
				Position = side == "R" and UDim2.new(1, 0, 0.5, 0) or UDim2.new(0, 0, 0.5, 0),
				Size = UDim2.new(0, 8, 1, 0),
				BackgroundColor3 = TAB_FILL,
				BackgroundTransparency = 1,
				BorderSizePixel = 0,
				ZIndex = 1,
				Parent = targetFill,
			})
		end

		tab.fill = fill
		tab.hlParts = { fill }
		if hasLeft then
			-- this tab meets a tab on its left -> square its left corner
			tab.hlParts[#tab.hlParts + 1] = squareOff(fill, "L")
			-- and the previous tab now has a neighbour on ITS right -> square that
			local prev = tabs[#tabs]
			prev.hlParts[#prev.hlParts + 1] = squareOff(prev.fill, "R")
			paintTab(prev, activeTab == prev, false)  -- show the new cover if prev is active
		end

		tab.button = btn
		tab.label = label
		-- no hover highlight on top tabs (only the active tab shows a fill)
		btn.MouseButton1Click:Connect(function() showTab(tab) end)
		paintTab(tab, false, false)

		-- this tab's sidebar column
		-- explicit pixel width + offset (NOT scale) so children can't overflow the
		-- card the way scale-width children do inside a ScrollingFrame
		tab.sidebarFrame = Create("Frame", {
			Position = UDim2.new(0, 12, 0, 12),
			Size = UDim2.new(0, SIDEBAR_W - 24, 0, 0),
			AutomaticSize = Enum.AutomaticSize.Y,
			BackgroundTransparency = 1,
			Visible = false,
			Parent = sidebarScroll,
		}, {
			Create("UIListLayout", { SortOrder = Enum.SortOrder.LayoutOrder, Padding = UDim.new(0, 3) }),
		})

		local groupCount = 0
		local standaloneStarted = false

		local function makePage(pname, popts, groupName, parentFrame)
			popts = popts or {}
			-- sub-tab row: plain text, no icon / accent bar (matches the mockup)
			local row = Create("TextButton", {
				Size = UDim2.new(1, 0, 0, 34),
				BackgroundColor3 = THEME.SidebarActive,
				BackgroundTransparency = 1,
				AutoButtonColor = false,
				Text = "",
				Parent = parentFrame or tab.sidebarFrame,
			}, { corner(8) })
			local label = Create("TextLabel", {
				BackgroundTransparency = 1,
				Position = UDim2.new(0, 14, 0, 0),
				Size = UDim2.new(1, -24, 1, 0),
				Font = FONT_MED,
				Text = tostring(pname or "Page"),
				TextColor3 = SIDEBAR_PAGE_TEXT,
				TextSize = 15,
				TextXAlignment = Enum.TextXAlignment.Left,
				TextTruncate = Enum.TextTruncate.AtEnd,
				Parent = row,
			})
			local pageBody = Create("ScrollingFrame", {
				Size = UDim2.new(1, 0, 1, 0),
				BackgroundTransparency = 1,
				BorderSizePixel = 0,
				ScrollBarThickness = 3,
				ScrollBarImageColor3 = THEME.Stroke,
				CanvasSize = UDim2.new(0, 0, 0, 0),
				AutomaticCanvasSize = Enum.AutomaticSize.Y,
				Visible = false,
				Parent = pagesHost,
			}, {
				Create("UIListLayout", { SortOrder = Enum.SortOrder.LayoutOrder }),
				Create("UIPadding", {
					PaddingLeft = UDim.new(0, 18), PaddingRight = UDim.new(0, 18),
					PaddingTop = UDim.new(0, 2), PaddingBottom = UDim.new(0, 16),
				}),
			})
			smoothScroll(pageBody)

			-- panels laid out across N columns (the one-pager grid)
			local ncols = math.clamp(math.floor(popts.columns or windowColumns), 1, 3)
			local COL_GAP = 10
			local colOff = math.floor(COL_GAP * (ncols - 1) / ncols + 0.5)
			local columnsHolder = Create("Frame", {
				Size = UDim2.new(1, 0, 0, 0),
				AutomaticSize = Enum.AutomaticSize.Y,
				BackgroundTransparency = 1,
				Parent = pageBody,
			}, {
				Create("UIListLayout", {
					FillDirection = Enum.FillDirection.Horizontal,
					Padding = UDim.new(0, COL_GAP),
					SortOrder = Enum.SortOrder.LayoutOrder,
					VerticalAlignment = Enum.VerticalAlignment.Top,
				}),
			})
			local pageCols, colCount = {}, {}
			for i = 1, ncols do
				pageCols[i] = Create("Frame", {
					Size = UDim2.new(1 / ncols, -colOff, 0, 0),
					AutomaticSize = Enum.AutomaticSize.Y,
					BackgroundTransparency = 1,
					LayoutOrder = i,
					Parent = columnsHolder,
				}, {
					Create("UIListLayout", { SortOrder = Enum.SortOrder.LayoutOrder, Padding = UDim.new(0, 10) }),
				})
				colCount[i] = 0
			end
			-- pick a column: explicit (column/side) or auto = fewest sections, ties left
			local function pickColumn(sopts)
				local idx
				if sopts and type(sopts.column) == "number" then
					idx = math.clamp(math.floor(sopts.column), 1, ncols)
				elseif sopts and sopts.side == "left" then
					idx = 1
				elseif sopts and sopts.side == "right" then
					idx = math.min(2, ncols)
				else
					idx = 1
					for i = 2, ncols do if colCount[i] < colCount[idx] then idx = i end end
				end
				colCount[idx] = colCount[idx] + 1
				return pageCols[idx]
			end

			local page = {
				name = tostring(pname or "Page"),
				group = groupName,
				row = row, label = label,
				body = pageBody, active = false,
			}
			table.insert(tab.pages, page)

			row.MouseEnter:Connect(function()
				if not page.active then tween(row, { BackgroundColor3 = THEME.SidebarHover, BackgroundTransparency = 0 }, TI.HOVER) end
			end)
			row.MouseLeave:Connect(function()
				if not page.active then tween(row, { BackgroundTransparency = 1 }, TI.HOVER) end
			end)
			row.MouseButton1Click:Connect(function() showPage(tab, page, true) end)

			-- page element API
			local Page = {}
			local defaultHost
			local function ensureDefault()
				if not defaultHost then defaultHost = makeSection(pickColumn({ column = 1 }), accent, nil) end
				return defaultHost
			end
			function Page.Section(t, sopts, ...)
				if t == Page then t, sopts = sopts, ... end -- tolerate Page:Section("X")
				return makeSection(pickColumn(sopts), accent, t)
			end
			Page.Button = function(a) return ensureDefault().Button(a) end
			Page.Toggle = function(a) return ensureDefault().Toggle(a) end
			Page.Slider = function(a) return ensureDefault().Slider(a) end
			Page.Dropdown = function(a) return ensureDefault().Dropdown(a) end
			Page.Input = function(a) return ensureDefault().Input(a) end
			Page.Keybind = function(a) return ensureDefault().Keybind(a) end
			Page.ColorPicker = function(a) return ensureDefault().ColorPicker(a) end
			Page.Paragraph = function(a) return ensureDefault().Paragraph(a) end
			Page.Label = function(a) return ensureDefault().Label(a) end

			-- first page becomes the tab's default
			if not tab.activePage then
				tab.activePage = page
				applyPageVisual(tab, page)
				if activeTab == tab then showPage(tab, page, false) end
			end
			return Page
		end

		local Tab = {}
		function Tab.Group(gname, ...)
			if gname == Tab then gname = ... end -- tolerate Tab:Group("X")
			groupCount = groupCount + 1
			-- hairline separating this group from the previous one
			if groupCount > 1 then
				Create("Frame", {
					Size = UDim2.new(1, 0, 0, 17),
					BackgroundTransparency = 1,
					Parent = tab.sidebarFrame,
				}, {
					Create("Frame", {
						AnchorPoint = Vector2.new(0.5, 0.5),
						Position = UDim2.new(0.5, 0, 0.5, 0),
						Size = UDim2.new(1, -8, 0, 1),
						BackgroundColor3 = THEME.RowDivider,
						BorderSizePixel = 0,
					}),
				})
			end
			local container = Create("Frame", {
				Size = UDim2.new(1, 0, 0, 0),
				AutomaticSize = Enum.AutomaticSize.Y,
				BackgroundTransparency = 1,
				Parent = tab.sidebarFrame,
			}, {
				Create("UIListLayout", { SortOrder = Enum.SortOrder.LayoutOrder, Padding = UDim.new(0, 6) }),
				Create("UIPadding", { PaddingTop = UDim.new(0, 2) }),
			})
			-- purple-tinted clickable header bar
			local header = Create("TextButton", {
				Size = UDim2.new(1, 0, 0, 32),
				BackgroundColor3 = Color3.fromRGB(41, 32, 66),
				BackgroundTransparency = 0.1,
				AutoButtonColor = false,
				Text = "",
				Parent = container,
			}, { corner(8), stroke(Color3.fromRGB(78, 56, 140), 1, 0.35), padXY(12, 0) })
			accentProp(Create("TextLabel", {
				AnchorPoint = Vector2.new(0, 0.5),
				Position = UDim2.new(0, 0, 0.5, 0),
				Size = UDim2.new(1, -22, 1, 0),
				BackgroundTransparency = 1,
				Font = FONT_BOLD,
				Text = string.upper(tostring(gname or "Group")),
				TextColor3 = accent,
				TextSize = 13,
				TextXAlignment = Enum.TextXAlignment.Left,
				Parent = header,
			}), "TextColor3", accent)
			local chev
			local chevSpec = resolveIcon("chevron-down")
			if chevSpec then
				chev = Create("ImageLabel", {
					AnchorPoint = Vector2.new(1, 0.5),
					Position = UDim2.new(1, 0, 0.5, 0),
					Size = UDim2.new(0, 14, 0, 14),
					BackgroundTransparency = 1,
					ImageColor3 = accent,
					Parent = header,
				})
				accentProp(chev, "ImageColor3", accent)
				applyIcon(chev, chevSpec)
			else
				chev = Create("TextLabel", {
					AnchorPoint = Vector2.new(1, 0.5),
					Position = UDim2.new(1, 0, 0.5, 0),
					Size = UDim2.new(0, 16, 1, 0),
					BackgroundTransparency = 1,
					Font = FONT_BOLD,
					Text = "\u{25BE}",
					TextColor3 = accent,
					TextSize = 15,
					Parent = header,
				})
			end
			-- collapsible pages holder
			local clip = Create("Frame", {
				Size = UDim2.new(1, 0, 0, 0),
				AutomaticSize = Enum.AutomaticSize.Y,
				BackgroundTransparency = 1,
				ClipsDescendants = true,
				Parent = container,
			})
			local holder = Create("Frame", {
				Size = UDim2.new(1, 0, 0, 0),
				AutomaticSize = Enum.AutomaticSize.Y,
				BackgroundTransparency = 1,
				Parent = clip,
			}, {
				Create("UIListLayout", { SortOrder = Enum.SortOrder.LayoutOrder, Padding = UDim.new(0, 3) }),
				Create("UIPadding", { PaddingTop = UDim.new(0, 6) }),
			})
			local open = true
			header.MouseButton1Click:Connect(function()
				open = not open
				tween(chev, { Rotation = open and 0 or 180 }, TI.FAST)
				if open then
					-- glide open to the measured content height, then hand back to
					-- AutomaticSize so it adapts to later content changes
					local target = 0
					pcall(function() target = holder.AbsoluteSize.Y end)
					clip.AutomaticSize = Enum.AutomaticSize.None
					tween(clip, { Size = UDim2.new(1, 0, 0, target) }, TI.EXPAND)
					task.delay(0.28, function() if open then clip.AutomaticSize = Enum.AutomaticSize.Y end end)
				else
					-- freeze current height, then glide closed to 0
					local cur = 0
					pcall(function() cur = clip.AbsoluteSize.Y end)
					clip.AutomaticSize = Enum.AutomaticSize.None
					clip.Size = UDim2.new(1, 0, 0, cur)
					tween(clip, { Size = UDim2.new(1, 0, 0, 0) }, TI.EXPAND)
				end
			end)
			local Group = {}
			function Group.Page(pname, popts, ...)
				if pname == Group then pname, popts = popts, ... end -- tolerate Group:Page("X")
				return makePage(pname, popts, gname, holder)
			end
			return Group
		end

		function Tab.Page(pname, popts, ...)
			if pname == Tab then pname, popts = popts, ... end -- tolerate Tab:Page("X")
			if not standaloneStarted and groupCount > 0 then
				standaloneStarted = true
				Create("Frame", { -- gap before standalone items
					Size = UDim2.new(1, 0, 0, 10),
					BackgroundTransparency = 1,
					Parent = tab.sidebarFrame,
				})
			end
			return makePage(pname, popts, nil)
		end

		table.insert(tabs, tab)
		if #tabs == 1 then showTab(tab) end
		return Tab
	end

	-- resize grip (bottom-right)
	-- minimum size keeps the whole top bar (logo, title, tabs, search, buttons)
	-- visible; below this the centred tabs would start to overlap
	local minW = IS_MOBILE and 480 or 820
	local minH = 380
	-- resize handle: a large invisible hit area + the curved corner icon
	local resizeGrip = Create("ImageButton", {
		Name = "ResizeGrip",
		AnchorPoint = Vector2.new(1, 1),
		Position = UDim2.new(1, -4, 1, -4),
		Size = UDim2.new(0, 54, 0, 54),
		BackgroundTransparency = 1,
		Image = "",
		AutoButtonColor = false,
		ZIndex = 7,
		Parent = root,
	})
	-- 9-sliced so the curved icon stretches cleanly toward the cursor
	local resizeIcon = Create("ImageLabel", {
		Name = "Icon",
		AnchorPoint = Vector2.new(1, 1),
		Position = UDim2.new(1, 0, 1, 0),
		Size = UDim2.new(0, 18, 0, 18),
		BackgroundTransparency = 1,
		Image = "rbxassetid://86527207319523",
		ImageColor3 = Color3.fromRGB(90, 90, 98),
		ImageTransparency = 0,
		ScaleType = Enum.ScaleType.Slice,
		SliceCenter = Rect.new(51, 52, 51, 52),
		SliceScale = 0.5,
		ZIndex = 8,
		Parent = resizeGrip,
	})
	do
		-- smooth resize: a RenderStepped loop where the visual size
		-- eases toward a cursor-driven target each frame (frame-rate independent
		-- exponential smoothing), so the window butter-glides to follow the cursor.
		local SMOOTH_K = 26          -- higher = tighter cursor-follow
		local resizing = false
		local hovering = false
		local startPointer, startW, startH
		local targetW, targetH = W, H
		local visualW, visualH = W, H
		local loopConn

		local function getPointer(input)
			if input and input.UserInputType == Enum.UserInputType.Touch then
				return Vector2.new(input.Position.X, input.Position.Y)
			end
			return UserInputService:GetMouseLocation()
		end
		local function maxSize()
			local vp = viewportSize()
			return math.max(minW, vp.X / scale - 40), math.max(minH, vp.Y / scale - 40)
		end
		-- grip stretch: normalize the cursor's position inside the grip, then
		-- stretch the icon NON-uniformly toward it (wider/taller as you move in)
		local function normResize()
			local mouse = UserInputService:GetMouseLocation()
			local insetY = 0
			pcall(function() insetY = game:GetService("GuiService"):GetGuiInset().Y end)
			local pos, sz = resizeGrip.AbsolutePosition, resizeGrip.AbsoluteSize
			local relX = (mouse.X - pos.X) / math.max(sz.X, 1)
			local relY = ((mouse.Y - insetY) - pos.Y) / math.max(sz.Y, 1)
			return Vector2.new(1 - math.clamp(relX, 0, 1), 1 - math.clamp(relY, 0, 1))
		end
		local function stretchIcon(duration)
			local n = normResize()
			tween(resizeIcon, {
				Size = UDim2.new(0, 20 + n.X * 30, 0, 20 + n.Y * 30),
				ImageColor3 = Color3.fromRGB(125, 125, 135),
			}, TweenInfo.new(duration or 0.18, Enum.EasingStyle.Quint, Enum.EasingDirection.Out))
		end
		local function pressIcon()
			tween(resizeIcon, {
				Size = UDim2.new(0, 30, 0, 30),
				ImageColor3 = Color3.fromRGB(150, 150, 160),
			}, TweenInfo.new(0.12, Enum.EasingStyle.Quint, Enum.EasingDirection.Out))
		end
		local function resetIcon()
			tween(resizeIcon, {
				Size = UDim2.new(0, 18, 0, 18),
				ImageColor3 = Color3.fromRGB(90, 90, 98),
			}, TweenInfo.new(0.18, Enum.EasingStyle.Quint, Enum.EasingDirection.Out))
		end
		local function stopLoop()
			if loopConn then loopConn:Disconnect(); loopConn = nil end
		end
		local function startLoop()
			stopLoop()
			visualW, visualH = W, H
			loopConn = RunService.RenderStepped:Connect(function(dt)
				local alpha = 1 - math.exp(-dt * SMOOTH_K)
				visualW = visualW + (targetW - visualW) * alpha
				visualH = visualH + (targetH - visualH) * alpha
				W, H = visualW, visualH
				root.Size = UDim2.new(0, visualW, 0, visualH)
				if not resizing
					and math.abs(visualW - targetW) <= 0.45
					and math.abs(visualH - targetH) <= 0.45 then
					W, H = targetW, targetH
					root.Size = UDim2.new(0, W, 0, H)
					stopLoop()
				end
			end)
		end

		resizeGrip.MouseEnter:Connect(function()
			hovering = true
			if not resizing then stretchIcon(0.18) end
		end)
		resizeGrip.MouseLeave:Connect(function()
			hovering = false
			if not resizing then resetIcon() end
		end)
		-- moving the cursor inside the grip restretches the icon toward it
		resizeGrip.InputChanged:Connect(function(input)
			if resizing then return end
			if input.UserInputType == Enum.UserInputType.MouseMovement
				or input.UserInputType == Enum.UserInputType.Touch then
				stretchIcon(0.14)
			end
		end)
		resizeGrip.InputBegan:Connect(function(input)
			if input.UserInputType == Enum.UserInputType.MouseButton1
				or input.UserInputType == Enum.UserInputType.Touch then
				resizing = true
				startPointer = getPointer(input)
				startW, startH = W, H
				targetW, targetH = W, H
				pressIcon()
				startLoop()
			end
		end)
		UserInputService.InputChanged:Connect(function(input)
			if not resizing then return end
			if input.UserInputType == Enum.UserInputType.MouseMovement
				or input.UserInputType == Enum.UserInputType.Touch then
				local delta = getPointer(input) - startPointer
				local maxW, maxH = maxSize()
				-- *2: window is centre-anchored, so the corner tracks the cursor
				targetW = math.clamp(startW + (delta.X / scale) * 2, minW, maxW)
				targetH = math.clamp(startH + (delta.Y / scale) * 2, minH, maxH)
			end
		end)
		UserInputService.InputEnded:Connect(function(input)
			if input.UserInputType == Enum.UserInputType.MouseButton1
				or input.UserInputType == Enum.UserInputType.Touch then
				if resizing then
					resizing = false
					if hovering then stretchIcon(0.18) else resetIcon() end
				end
			end
		end)
	end

	-- minimize / restore, close, hide-key, mobile reopen
	local minimized = false
	local function setMinimized(m)
		minimized = m
		closeOpenDropdown()
		if resizeGrip then resizeGrip.Visible = not m end
		if m then
			topbarFiller.Visible = false
			tween(root, { Size = UDim2.new(0, W, 0, TOPBAR_H) }, TI.OPEN)
			setMinIcon("plus", "\u{002B}")
		else
			topbarFiller.Visible = true
			tween(root, { Size = UDim2.new(0, W, 0, H) }, TI.OPEN)
			setMinIcon("minus", "\u{2013}")
		end
	end
	function Win.Toggle(force)
		setMinimized((force == nil) and (not minimized) or (not force))
	end
	minBtn.MouseButton1Click:Connect(function() setMinimized(not minimized) end)

	function Win.Destroy()
		if fpsConn then pcall(function() fpsConn:Disconnect() end); fpsConn = nil end
		closeOpenDropdown()
		tween(root, { Size = UDim2.new(0, W, 0, 0) }, TI.SLIDE)
		task.delay(0.25, function() if root then root:Destroy() end end)
	end
	Win.Unload = Win.Destroy
	closeBtn.MouseButton1Click:Connect(function() Win.Destroy() end)

	local hidden = false
	local function setHidden(hide)
		hidden = hide
		if hide then
			tween(root, { Size = UDim2.new(0, W, 0, 0) }, TI.SLIDE)
			task.delay(0.2, function() if hidden then root.Visible = false end end)
		else
			root.Visible = true
			minimized = false
			tween(root, { Size = UDim2.new(0, W, 0, H) }, TI.OPEN)
		end
	end
	local toggleKey = opts.toggleKey or Enum.KeyCode.RightShift
	UserInputService.InputBegan:Connect(function(input, gpe)
		if gpe then return end
		if input.KeyCode == toggleKey then
			setHidden(not hidden)
		elseif input.KeyCode == Enum.KeyCode.K then
			local ok, down = pcall(function()
				return UserInputService:IsKeyDown(Enum.KeyCode.LeftControl)
					or UserInputService:IsKeyDown(Enum.KeyCode.RightControl)
			end)
			if ok and down then openSearch() end
		elseif input.KeyCode == Enum.KeyCode.Escape then
			closeSearch()
		end
	end)

	if IS_MOBILE then
		local fab = Create("TextButton", {
			Name = "Reopen",
			Position = UDim2.new(0, 12, 0, 12),
			Size = UDim2.new(0, 44, 0, 44),
			BackgroundColor3 = accent,
			Font = FONT_BOLD,
			Text = "N",
			TextColor3 = THEME.Text,
			TextSize = 21,
			Parent = screenGui,
		}, { corner(22), stroke(THEME.Stroke, 1, 0.4) })
		makeDraggable(fab, fab)
		fab.MouseButton1Click:Connect(function() setHidden(not hidden) end)
	end

	-- recolor the logo at runtime (any hue): Win.SetLogoColor(Color3.fromRGB(...))
	function Win.SetLogoColor(c)
		logoColor = c or logoColor
		if logoGrad then logoGrad.Enabled = false end
		if logoImage then logoImage.ImageColor3 = logoColor end
	end
	-- recolor the logo with a gradient: Win.SetLogoGradient(c1, c2)
	function Win.SetLogoGradient(c1, c2)
		if not (logoImage and logoGrad and c1 and c2) then return end
		logoGrad.Color = ColorSequence.new(c1, c2)
		logoGrad.Enabled = true
		logoImage.ImageColor3 = Color3.new(1, 1, 1)
	end

	-- live-recolor the whole menu's accent (Win.SetAccent(Color3))
	function Win.SetAccent(c)
		if not c then return end
		accent = c
		THEME.Accent = c
		for _, fn in ipairs(accentHooks) do pcall(fn, c) end
		-- re-apply the dynamic accent text (active sub-tab + breadcrumb)
		if activeTab and activeTab.activePage then
			pcall(function() applyPageVisual(activeTab, activeTab.activePage, false) end)
			pcall(function() setCrumb(activeTab, activeTab.activePage) end)
		end
	end

	Win.Instance = root
	Win.Notify = NEMESIS.Notify
	return Win
end

return NEMESIS

end)()

--[[
	NEMESIS - full showcase
	Loadstring this in your executor to see every element, every mode, and the
	programmatic API in one window.

	Controls:
	  RightShift            hide / show the menu
	  Ctrl + K              focus the search box
	  drag bottom-right     smooth resize
	  minus / x             minimize / close
]]

-- ?_=os.time() busts the GitHub / executor cache so you always pull the latest

local function notify(title, content, duration)
	NEMESIS.Notify({ title = title, content = content, duration = duration or 3 })
end

local Win = NEMESIS.Window({
	title = "NEMESIS",
	accent = Color3.fromRGB(140, 90, 255),   -- purple accent
	columns = 2,                              -- panels per page (desktop)
	toggleKey = Enum.KeyCode.RightShift,
	game = "Showcase",                        -- sidebar footer, first line
	status = "All systems live",              -- sidebar footer, second line
	configs = { "default" },                  -- header config pill starts with this
	-- key = { key = "hello123", note = "Demo key gate." }, -- uncomment to try the key system
	-- logoColor = Color3.fromRGB(150, 85, 255), -- optional: recolor the N logo
})

-- TAB 1 : ELEMENTS  (one of every control, with its options)
local Elements = Win.Tab("Elements", "layout-grid")
local Basics = Elements.Group("BASICS")

-- Page: Buttons and Toggles -------------------------------------------
local BT = Basics.Page("Buttons", { icon = "mouse-pointer-click" })
local s_btn = BT.Section("BUTTONS")
s_btn.Button({ text = "Plain Button", button = "Run", callback = function()
	notify("Button", "You clicked the button.", 2)
end })
s_btn.Button({ text = "Button with description", desc = "Buttons can carry a second line.", button = "Go",
	callback = function() notify("Button", "Second button fired.", 2) end })
s_btn.Label("This is a Label. Small muted text inside a section.")
s_btn.Paragraph({ title = "Paragraph", content = "A Paragraph has a title plus a longer wrapping body of text, useful for notes, credits, or instructions." })

local s_tog = BT.Section("TOGGLES")
s_tog.Toggle({ text = "Toggle (off by default)", default = false, flag = "sc_t_off",
	callback = function(v) notify("Toggle", "off-default is now " .. tostring(v), 1.5) end })
s_tog.Toggle({ text = "Toggle (on by default)", default = true, flag = "sc_t_on" })
s_tog.Toggle({ text = "Toggle with description", desc = "A checkbox-style toggle.", default = false, flag = "sc_t_desc" })

-- Page: Sliders -------------------------------------------------------
local SL = Basics.Page("Sliders", { icon = "sliders-horizontal" })
local s_sl = SL.Section("SLIDERS")
s_sl.Slider({ text = "Integer 0 to 250", min = 0, max = 250, default = 100, increment = 1, flag = "sc_s_int" })
s_sl.Slider({ text = "Percent", min = 0, max = 100, default = 50, increment = 5, suffix = "%", flag = "sc_s_pct" })
s_sl.Slider({ text = "Degrees", min = 0, max = 360, default = 90, increment = 15, suffix = "deg", flag = "sc_s_deg" })
s_sl.Slider({ text = "Decimal", min = 0, max = 1, default = 0.65, increment = 0.01, flag = "sc_s_dec" })
s_sl.Slider({ text = "With description", desc = "Drag the handle or click the track.", min = 0, max = 10, default = 3, increment = 1, flag = "sc_s_desc" })

-- Page: Dropdowns -----------------------------------------------------
local DD = Basics.Page("Dropdowns", { icon = "list" })
local s_single = DD.Section("SINGLE SELECT")
s_single.Dropdown({ text = "Quality", options = { "Low", "Medium", "High", "Ultra" }, default = "Medium", flag = "sc_dd_single",
	callback = function(v) notify("Dropdown", "Chose " .. tostring(v), 1.5) end })
s_single.Dropdown({ text = "No default", options = { "First", "Second", "Third" }, flag = "sc_dd_nodef" })

local s_multi = DD.Section("MULTI SELECT")
s_multi.Dropdown({ text = "Hitboxes", options = { "Head", "Neck", "Chest", "Stomach", "Pelvis", "Arms", "Legs" },
	multi = true, default = { "Head", "Chest" }, flag = "sc_dd_multi",
	callback = function(list) notify("Multi", table.concat(list, ", "), 2) end })

-- Page: Text and Keys -------------------------------------------------
local IN = Basics.Page("Text and Keys", { icon = "keyboard" })
local s_in = IN.Section("INPUTS")
s_in.Input({ text = "Name", placeholder = "type here...", default = "", clearOnFocus = false, flag = "sc_in_name",
	callback = function(t) notify("Input", "You typed: " .. t, 2) end })
s_in.Input({ text = "Clears on focus", placeholder = "click me", clearOnFocus = true, flag = "sc_in_clear" })

local s_kb = IN.Section("KEYBINDS")
s_kb.Keybind({ text = "Toggle mode (E)", default = Enum.KeyCode.E, mode = "Toggle", flag = "sc_kb_toggle",
	callback = function(state) notify("Keybind / Toggle", "state = " .. tostring(state), 1.5) end })
s_kb.Keybind({ text = "Hold mode (F)", default = Enum.KeyCode.F, mode = "Hold", flag = "sc_kb_hold",
	callback = function(down) notify("Keybind / Hold", down and "DOWN" or "up", 1) end })
s_kb.Keybind({ text = "Always mode (G)", default = Enum.KeyCode.G, mode = "Always", flag = "sc_kb_always",
	callback = function() notify("Keybind / Always", "fired", 1) end })
s_kb.Keybind({ text = "Mouse button", default = "MOUSE5", mode = "Hold", flag = "sc_kb_mouse" })

-- Page: Colors --------------------------------------------------------
local CO = Basics.Page("Colors", { icon = "palette" })
local s_co = CO.Section("COLOR PICKERS")
s_co.ColorPicker({ text = "Solid color", default = Color3.fromRGB(255, 0, 80), transparency = 0, flag = "sc_c_solid",
	callback = function(color, alpha) notify("Color", "alpha = " .. tostring(alpha), 1.5) end })
s_co.ColorPicker({ text = "With transparency", default = Color3.fromRGB(0, 200, 255), transparency = 0.3, flag = "sc_c_alpha" })
s_co.ColorPicker({ text = "Gradient color", gradient = true, default = Color3.fromRGB(255, 0, 0), gradientDefault = Color3.fromRGB(0, 0, 255), flag = "sc_c_grad" })
s_co.Label("Right-click a swatch to copy its hex. In gradient mode you get two swatches; right-click a saved swatch to remove it.")
s_co.Divider({ text = "MENU THEME" })
s_co.ColorPicker({ text = "Menu accent (live)", default = Color3.fromRGB(140, 90, 255), flag = "sc_accent",
	callback = function(color) Win.SetAccent(color) end })

-- Page: Lists (Divider + Listbox)
local LB = Basics.Page("Lists", { icon = "list-checks" })
local s_lb = LB.Section("LISTBOX")
s_lb.Listbox({ text = "Single select", options = { "Aimbot", "Triggerbot", "Backtrack", "Anti-Aim", "Fakelag" }, default = "Aimbot", rows = 4,
	callback = function(v) notify("Listbox", "chose " .. tostring(v), 1.5) end })
s_lb.Divider()
s_lb.Listbox({ text = "Multi select", options = { "Head", "Neck", "Chest", "Stomach", "Pelvis", "Arms", "Legs" }, multi = true, default = { "Head", "Chest" }, rows = 4,
	callback = function(list) notify("Listbox", table.concat(list, ", "), 2) end })

-- Standalone page (renders below the group, no group header) -----------
local Info = Elements.Page("Info", { icon = "info" })
local s_info = Info.Section("ABOUT")
s_info.Paragraph({ title = "Standalone pages", content = "Pages added with Tab.Page (instead of Group.Page) render below the groups, like this one." })
s_info.Label("Every flag value lives in NEMESIS.Flags, keyed by its flag name.")

-- TAB 2 : LAYOUT  (groups, dividers, and the two-column grid)
local Layout = Win.Tab("Layout", "columns-2")

local Combat = Layout.Group("COMBAT")
local Aim = Combat.Page("Aimbot", { icon = "crosshair" })
local s_aim = Aim.Section("AIMBOT")
s_aim.Toggle({ text = "Enable", default = true, flag = "sc_aim" })
s_aim.Slider({ text = "FOV", min = 0, max = 180, default = 120, suffix = "deg", flag = "sc_fov" })
s_aim.Dropdown({ text = "Target", options = { "Closest", "Health", "Distance" }, default = "Closest", flag = "sc_target" })

local Visuals = Layout.Group("VISUALS")
local Esp = Visuals.Page("ESP", { icon = "eye" })
local s_esp = Esp.Section("ESP")
s_esp.Toggle({ text = "Enabled", default = true, flag = "sc_esp" })
s_esp.ColorPicker({ text = "Box color", default = Color3.fromRGB(120, 255, 120), flag = "sc_esp_col" })
s_esp.Keybind({ text = "Toggle ESP", default = Enum.KeyCode.V, mode = "Toggle", flag = "sc_esp_key" })

-- Standalone item under the Layout tab
local Extra = Layout.Page("Extra", { icon = "more-horizontal" })
local s_extra = Extra.Section("MISC")
s_extra.Toggle({ text = "Lazy-section toggle", default = false, flag = "sc_lazy" })

-- Explicit two-column page with manual section placement
local Grid = Layout.Page("Grid", { icon = "grid-2x2", columns = 2 })
local gridL = Grid.Section("LEFT COLUMN")               -- auto-placed (column 1)
gridL.Toggle({ text = "Auto column 1", default = true, flag = "sc_grid_a" })
gridL.Slider({ text = "Value", min = 0, max = 100, default = 40, flag = "sc_grid_v" })
local gridR = Grid.Section("RIGHT COLUMN", { column = 2 }) -- forced into column 2
gridR.Toggle({ text = "Manual column 2", default = false, flag = "sc_grid_b" })
gridR.Dropdown({ text = "Mode", options = { "A", "B", "C" }, default = "A", flag = "sc_grid_m" })

-- TAB 3 : CONTROL  (programmatic Set / Get and SetOptions)
local Control = Win.Tab("Control", "settings-2")
local Live = Control.Page("Live", { icon = "activity" })

local s_driven = Live.Section("DRIVEN BY BUTTONS")
local liveToggle = s_driven.Toggle({ text = "Controlled toggle", default = false, flag = "sc_ctl_toggle" })
local liveSlider = s_driven.Slider({ text = "Controlled slider", min = 0, max = 100, default = 0, flag = "sc_ctl_slider" })
local liveDrop   = s_driven.Dropdown({ text = "Controlled dropdown", options = { "A", "B", "C" }, default = "A", flag = "sc_ctl_drop" })

local s_actions = Live.Section("ACTIONS")
s_actions.Button({ text = "Toggle ON", button = "On", callback = function() liveToggle.Set(true) end })
s_actions.Button({ text = "Toggle OFF", button = "Off", callback = function() liveToggle.Set(false) end })
s_actions.Button({ text = "Slider = 75", button = "75", callback = function() liveSlider.Set(75) end })
s_actions.Button({ text = "Dropdown = C", button = "C", callback = function() liveDrop.Set("C") end })
s_actions.Button({ text = "Swap dropdown options", button = "Swap", callback = function()
	liveDrop.SetOptions({ "X", "Y", "Z", "W" })
	notify("SetOptions", "Dropdown options replaced.", 2)
end })
s_actions.Button({ text = "Read all values", button = "Read", callback = function()
	notify("Get()",
		"toggle=" .. tostring(liveToggle.Get())
		.. "  slider=" .. tostring(liveSlider.Get())
		.. "  drop=" .. tostring(liveDrop.Get()), 4)
end })

-- TAB 4 : CONFIG  (logo recolor, accent presets, notifications)
local Config = Win.Tab("Config", "settings")
local Cfg = Config.Page("Interface", { icon = "palette" })

local s_logo = Cfg.Section("LOGO")
s_logo.ColorPicker({ text = "Logo color", default = Color3.fromRGB(150, 85, 255), transparency = 0, flag = "sc_logo",
	callback = function(color) Win.SetLogoColor(color) end })
s_logo.Dropdown({ text = "Logo preset", options = { "Purple", "Red", "Pink", "Green", "Cyan", "White" }, default = "Purple", flag = "sc_logo_preset",
	callback = function(v)
		local map = {
			Purple = Color3.fromRGB(150, 85, 255), Red = Color3.fromRGB(255, 45, 45),
			Pink = Color3.fromRGB(255, 90, 200), Green = Color3.fromRGB(90, 255, 120),
			Cyan = Color3.fromRGB(60, 220, 255), White = Color3.fromRGB(245, 245, 250),
		}
		Win.SetLogoColor(map[v])
	end })
s_logo.ColorPicker({ text = "Logo gradient", gradient = true, default = Color3.fromRGB(170, 100, 255), gradientDefault = Color3.fromRGB(255, 70, 160), flag = "sc_logo_grad",
	callback = function(colors) if type(colors) == "table" then Win.SetLogoGradient(colors[1], colors[2]) end end })
s_logo.Button({ text = "Reset logo to solid", button = "Reset", callback = function() Win.SetLogoColor(Color3.fromRGB(150, 85, 255)) end })

local s_note = Cfg.Section("NOTIFICATIONS")
s_note.Button({ text = "Short notification", button = "2s", callback = function() notify("Heads up", "This one lasts two seconds.", 2) end })
s_note.Button({ text = "Long notification", button = "6s", callback = function() notify("Reminder", "This one sticks around for six seconds.", 6) end })
s_note.Input({ text = "Custom message", placeholder = "type then press Send", flag = "sc_note_msg" })
s_note.Button({ text = "Send custom", button = "Send", callback = function()
	local msg = NEMESIS.Flags.sc_note_msg
	notify("Custom", (msg ~= nil and msg ~= "" and msg) or "Type something in the box above.", 3)
end })

local s_theme = Cfg.Section("THEME")
s_theme.Dropdown({ text = "Menu theme", options = { "Dark", "Midnight", "Abyss", "Light" }, default = "Dark", flag = "sc_theme",
	callback = function(v) Win.SetTheme(v) end })
s_theme.Label("The whole menu recolors live. Your accent stays put.")

local s_save = Cfg.Section("CONFIGS")
s_save.Label("Everything with a flag saves: toggles, sliders, colors, gradients, keybinds. Use the pill in the header, or these:")
s_save.Button({ text = "Save as showcase.json", button = "Save", callback = function()
	if Win.SaveConfig("showcase") then notify("Config", "Saved as showcase.", 2) end
end })
s_save.Button({ text = "Load showcase.json", button = "Load", callback = function()
	if Win.LoadConfig("showcase") then notify("Config", "Loaded showcase.", 2) end
end })
s_save.Button({ text = "Autoload showcase.json", button = "Mark", callback = function()
	Win.SetAutoload("showcase")
	notify("Config", "showcase loads on every start.", 2)
end })

local s_credits = Cfg.Section("ABOUT")
s_credits.Paragraph({ title = "NEMESIS", content = "idk" })

NEMESIS.Notify({ title = "NEMESIS", content = "Showcase loaded. Explore every tab.", duration = 5 })
